use std::future::Future;
use std::sync::Mutex;

pub trait MetricsSink {
    fn publish(&self, label: &str, value: u64) -> impl Future<Output = ()>;
}

pub struct MetricsCollector<S: MetricsSink> {
    counts: Mutex<HashMap<String, u64>>,
    sink: S,
}

